// Recupera o placar da execução anterior (garantindo que sejam números)
const anterior = flow.get('placar_anterior') || { gols_mandante: 0, gols_visitante: 0 };
const novo = msg.payload;

// CONVERSÃO: Transforma as strings numéricas do JSON em Inteiros
const novosGolsM = parseInt(novo.gols_mandante) || 0;
const novosGolsV = parseInt(novo.gols_visitante) || 0;
const antGolsM = parseInt(anterior.gols_mandante) || 0;
const antGolsV = parseInt(anterior.gols_visitante) || 0;

let timeIdQueMarcou = null;
let nomeTimeQueMarcou = "";

// Verifica se houve gol do mandante
if (novosGolsM > antGolsM) {
    timeIdQueMarcou = parseInt(novo.mandante_id); // Garante que o ID vire número puro
    nomeTimeQueMarcou = novo.mandante_nome;
}
// Verifica se houve gol do visitante
else if (novosGolsV > antGolsV) {
    timeIdQueMarcou = parseInt(novo.visitante_id); // Garante que o ID vire número puro
    nomeTimeQueMarcou = novo.visitante_nome;
}

// Atualiza o estado global com os novos valores numéricos para a próxima comparação
flow.set('placar_anterior', {
    gols_mandante: novosGolsM,
    gols_visitante: novosGolsV
});

// Se um gol foi detectado, prossegue com o fluxo
if (timeIdQueMarcou) {
    msg.params = [timeIdQueMarcou]; // Mandará o número limpo (ex: 3 ou 5)
    msg.nomeTime = nomeTimeQueMarcou;
    return msg;
} else {
    return null;
}

const row = msg.payload;
const deviceId = row.device_id;
const nomeTime = msg.nomeTime; // Capturamos o nome definido no passo anterior

const mqttMsg = {
    topic: 'copoAlertas',
    payload: ({
        mensagem: "Gol do " + nomeTime,
        target_device: deviceId
    }),
    qos: 1,
    retain: false
};

return mqttMsg;
